pragma solidity 0.6.11;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "./aave/ILendingPoolAddressesProvider.sol";
import "./aave/ILendingPool.sol";
import "./aave/AToken.sol";




contract GoodGhosting is Ownable, Pausable {
    using SafeMath for uint256;


    bool public redeemed;

    uint256 public totalGameInterest;

    uint256 public totalGamePrincipal;

    uint256 public adminFeeAmount;

    bool public adminWithdraw;

    uint256 public totalIncentiveAmount = 0;

    uint256 public activePlayersCount = 0;


    IERC20 public immutable daiToken;

    AToken public immutable adaiToken;

    ILendingPoolAddressesProvider public immutable lendingPoolAddressProvider;

    ILendingPool public lendingPool;

    uint256 public immutable segmentPayment;

    uint256 public immutable lastSegment;

    uint256 public immutable firstSegmentStart;

    uint256 public immutable segmentLength;

    uint256 public immutable earlyWithdrawalFee;

    uint256 public immutable customFee;

    uint256 public immutable maxPlayersCount;

    IERC20 public immutable incentiveToken;

    struct Player {
        address addr;
        bool withdrawn;
        bool canRejoin;
        uint256 mostRecentSegmentPaid;
        uint256 amountPaid;
    }

    mapping(address => Player) public players;


    address[] public iterablePlayers;

    address[] public winners;

    event JoinedGame(address indexed player, uint256 amount);
    event Deposit(
        address indexed player,
        uint256 indexed segment,
        uint256 amount
    );
    event Withdrawal(
        address indexed player,
        uint256 amount,
        uint256 playerReward,
        uint256 playerIncentive
    );
    event FundsRedeemedFromExternalPool(
        uint256 totalAmount,
        uint256 totalGamePrincipal,
        uint256 totalGameInterest,
        uint256 rewards,
        uint256 totalIncentiveAmount
    );
    event WinnersAnnouncement(address[] winners);
    event EarlyWithdrawal(
        address indexed player,
        uint256 amount,
        uint256 totalGamePrincipal
    );
    event AdminWithdrawal(
        address indexed admin,
        uint256 totalGameInterest,
        uint256 adminFeeAmount,
        uint256 adminIncentiveAmount
    );

    modifier whenGameIsCompleted() {
        require(isGameCompleted(), "Game is not completed");
        _;
    }

    modifier whenGameIsNotCompleted() {
        require(!isGameCompleted(), "Game is already completed");
        _;
    }


    constructor(
        IERC20 _inboundCurrency,
        ILendingPoolAddressesProvider _lendingPoolAddressProvider,
        uint256 _segmentCount,
        uint256 _segmentLength,
        uint256 _segmentPayment,
        uint256 _earlyWithdrawalFee,
        uint256 _customFee,
        address _dataProvider,
        uint256 _maxPlayersCount,
        IERC20 _incentiveToken
    ) public {
        require(_customFee <= 20, "_customFee must be less than or equal to 20%");
        require(_earlyWithdrawalFee <= 10, "_earlyWithdrawalFee must be less than or equal to 10%");
        require(_earlyWithdrawalFee > 0,  "_earlyWithdrawalFee must be greater than zero");
        require(_maxPlayersCount > 0, "_maxPlayersCount must be greater than zero");
        require(address(_inboundCurrency) != address(0), "invalid _inboundCurrency address");
        require(address(_lendingPoolAddressProvider) != address(0), "invalid _lendingPoolAddressProvider address");
        require(_segmentCount > 0, "_segmentCount must be greater than zero");
        require(_segmentLength > 0, "_segmentLength must be greater than zero");
        require(_segmentPayment > 0, "_segmentPayment must be greater than zero");
        require(_dataProvider != address(0), "invalid _dataProvider address");

        firstSegmentStart = block.timestamp; 
        lastSegment = _segmentCount;
        segmentLength = _segmentLength;
        segmentPayment = _segmentPayment;
        earlyWithdrawalFee = _earlyWithdrawalFee;
        customFee = _customFee;
        daiToken = _inboundCurrency;
        lendingPoolAddressProvider = _lendingPoolAddressProvider;
        AaveProtocolDataProvider dataProvider =
            AaveProtocolDataProvider(_dataProvider);

        lendingPool = ILendingPool(
            _lendingPoolAddressProvider.getLendingPool()
        );

        (address adaiTokenAddress, , ) =
            dataProvider.getReserveTokensAddresses(address(_inboundCurrency));
        adaiToken = AToken(adaiTokenAddress);
        maxPlayersCount = _maxPlayersCount;
        incentiveToken = _incentiveToken;
    }


    function pause() external onlyOwner whenNotPaused {
        _pause();
    }


    function unpause() external onlyOwner whenPaused {
        _unpause();
    }



    function adminFeeWithdraw() external virtual onlyOwner whenGameIsCompleted {
        require(redeemed, "Funds not redeemed from external pool");
        require(!adminWithdraw, "Admin has already withdrawn");
        adminWithdraw = true;



        uint256 adminIncentiveAmount = 0;
        if (winners.length == 0 && totalIncentiveAmount > 0) {
            adminIncentiveAmount = totalIncentiveAmount;
        }

        emit AdminWithdrawal(owner(), totalGameInterest, adminFeeAmount, adminIncentiveAmount);

        if (adminFeeAmount > 0) {
            require(
                IERC20(daiToken).transfer(owner(), adminFeeAmount),
                "Fail to transfer ER20 tokens to admin"
            );
        }

        if (adminIncentiveAmount > 0) {
            require(
                IERC20(incentiveToken).transfer(owner(), adminIncentiveAmount),
                "Fail to transfer ER20 incentive tokens to admin"
            );
        }
    }


    function joinGame()
        external
        virtual
        whenNotPaused
    {
        _joinGame();
    }



    function earlyWithdraw() external whenNotPaused whenGameIsNotCompleted {
        Player storage player = players[msg.sender];
        require(player.amountPaid > 0, "Player does not exist");
        require(!player.withdrawn, "Player has already withdrawn");
        player.withdrawn = true;
        activePlayersCount = activePlayersCount.sub(1);


        uint256 withdrawAmount =
            player.amountPaid.sub(
                player.amountPaid.mul(earlyWithdrawalFee).div(100)
            );

        totalGamePrincipal = totalGamePrincipal.sub(player.amountPaid);
        uint256 currentSegment = getCurrentSegment();


        if (currentSegment == 0) {
            player.canRejoin = true;
        }

        emit EarlyWithdrawal(msg.sender, withdrawAmount, totalGamePrincipal);

        lendingPool.withdraw(address(daiToken), withdrawAmount, address(this));
        require(
            IERC20(daiToken).transfer(msg.sender, withdrawAmount),
            "Fail to transfer ERC20 tokens on early withdraw"
        );
    }


    function withdraw() external virtual {
        Player storage player = players[msg.sender];
        require(player.amountPaid > 0, "Player does not exist");
        require(!player.withdrawn, "Player has already withdrawn");
        player.withdrawn = true;


        if (!redeemed) {
            redeemFromExternalPool();
        }

        uint256 payout = player.amountPaid;
        uint256 playerIncentive = 0;
        if (player.mostRecentSegmentPaid == lastSegment.sub(1)) {

            payout = payout.add(totalGameInterest.div(winners.length));

            if (totalIncentiveAmount > 0) {
                playerIncentive = totalIncentiveAmount.div(winners.length);
            }
        }
        emit Withdrawal(msg.sender, payout, 0, playerIncentive);

        require(
            IERC20(daiToken).transfer(msg.sender, payout),
            "Fail to transfer ERC20 tokens on withdraw"
        );

        if (playerIncentive > 0) {
            require(
                IERC20(incentiveToken).transfer(msg.sender, playerIncentive),
                "Fail to transfer ERC20 incentive tokens on withdraw"
            );
        }
    }


    function makeDeposit() external whenNotPaused {
        require(
            !players[msg.sender].withdrawn,
            "Player already withdraw from game"
        );

        require(
            players[msg.sender].addr == msg.sender,
            "Sender is not a player"
        );

        uint256 currentSegment = getCurrentSegment();







        require(
            currentSegment > 0 && currentSegment < lastSegment,
            "Deposit available only between segment 1 and segment n-1 (penultimate)"
        );


        require(
            players[msg.sender].mostRecentSegmentPaid != currentSegment,
            "Player already paid current segment"
        );


        require(
            players[msg.sender].mostRecentSegmentPaid == currentSegment.sub(1),
            "Player didn't pay the previous segment - game over!"
        );


        if (currentSegment == lastSegment.sub(1)) {
            winners.push(msg.sender);
        }

        emit Deposit(msg.sender, currentSegment, segmentPayment);
        _transferDaiToContract();
    }



    function getNumberOfPlayers() external view returns (uint256) {
        return iterablePlayers.length;
    }



    function redeemFromExternalPool() public virtual whenGameIsCompleted {
        require(!redeemed, "Redeem operation already happened for the game");
        redeemed = true;

        if (adaiToken.balanceOf(address(this)) > 0) {
            lendingPool.withdraw(
                address(daiToken),
                type(uint256).max,
                address(this)
            );
        }
        uint256 totalBalance = IERC20(daiToken).balanceOf(address(this));

        if (address(incentiveToken) != address(0)) {
            totalIncentiveAmount = IERC20(incentiveToken).balanceOf(address(this));
        }


        uint256 grossInterest = 0;




        if (totalBalance > totalGamePrincipal) {
            grossInterest = totalBalance.sub(totalGamePrincipal);
        }


        uint256 _adminFeeAmount;
        if (customFee > 0) {
            _adminFeeAmount = (grossInterest.mul(customFee)).div(100);
            totalGameInterest = grossInterest.sub(_adminFeeAmount);
        } else {
            _adminFeeAmount = 0;
            totalGameInterest = grossInterest;
        }


        if (winners.length == 0) {
            adminFeeAmount = grossInterest;
        } else {
            adminFeeAmount = _adminFeeAmount;
        }

        emit FundsRedeemedFromExternalPool(
            totalBalance,
            totalGamePrincipal,
            totalGameInterest,
            0,
            totalIncentiveAmount
        );
        emit WinnersAnnouncement(winners);
    }



    function getCurrentSegment() public view returns (uint256) {
        return block.timestamp.sub(firstSegmentStart).div(segmentLength);
    }



    function isGameCompleted() public view returns (bool) {

        return getCurrentSegment() > lastSegment;
    }


    function _transferDaiToContract() internal {
        require(
            daiToken.allowance(msg.sender, address(this)) >= segmentPayment,
            "You need to have allowance to do transfer DAI on the smart contract"
        );

        uint256 currentSegment = getCurrentSegment();
        players[msg.sender].mostRecentSegmentPaid = currentSegment;
        players[msg.sender].amountPaid = players[msg.sender].amountPaid.add(
            segmentPayment
        );
        totalGamePrincipal = totalGamePrincipal.add(segmentPayment);
        require(
            daiToken.transferFrom(msg.sender, address(this), segmentPayment),
            "Transfer failed"
        );



        uint256 contractBalance = daiToken.balanceOf(address(this));
        require(
            daiToken.approve(address(lendingPool), contractBalance),
            "Fail to approve allowance to lending pool"
        );

        lendingPool.deposit(address(daiToken), contractBalance, address(this), 155);
    }


    function _joinGame() internal {
        require(getCurrentSegment() == 0, "Game has already started");
        require(
            players[msg.sender].addr != msg.sender ||
                players[msg.sender].canRejoin,
            "Cannot join the game more than once"
        );

        activePlayersCount = activePlayersCount.add(1);
        require(activePlayersCount <= maxPlayersCount, "Reached max quantity of players allowed");

        bool canRejoin = players[msg.sender].canRejoin;
        Player memory newPlayer =
            Player({
                addr: msg.sender,
                mostRecentSegmentPaid: 0,
                amountPaid: 0,
                withdrawn: false,
                canRejoin: false
            });
        players[msg.sender] = newPlayer;
        if (!canRejoin) {
            iterablePlayers.push(msg.sender);
        }
        emit JoinedGame(msg.sender, segmentPayment);
        _transferDaiToContract();
    }
}

pragma solidity ^0.7.6;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts-upgradeable/proxy/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import "hardhat-deploy/solc_0.7/proxy/Proxied.sol";

import "./interfaces/ILayerZeroRelayer.sol";
import "./interfaces/ILayerZeroUltraLightNodeV1.sol";

contract Relayer is ILayerZeroRelayer, ReentrancyGuard, OwnableUpgradeable, Proxied {
    using SafeERC20 for IERC20;

    using SafeMath for uint;
    using SafeMath for uint128;
    using SafeMath for uint64;

    ILayerZeroUltraLightNodeV1 public uln;

    struct DstPrice {
        uint128 dstPriceRatio; 
        uint128 dstGasPriceInWei;
    }

    struct DstConfig {
        uint128 dstNativeAmtCap;
        uint64 baseGas;
        uint64 gasPerByte;
    }


    mapping(uint16 => DstPrice) public dstPriceLookup;

    mapping(uint16 => mapping(uint16 => DstConfig)) public dstConfigLookup;

    mapping(address => bool) public approvedAddresses;

    event WithdrawTokens(address token, address to, uint amount);
    event Withdraw(address to, uint amount);
    event ApproveAddress(address addr, bool approved);


    modifier onlyApproved() {
        if (owner() != msg.sender) {
            require(isApproved(msg.sender), "Relayer: not approved");
        }
        _;
    }

    function initialize(address _uln) public proxied initializer {
        __Ownable_init();
        uln = ILayerZeroUltraLightNodeV1(_uln);
        setApprovedAddress(address(this), true);
    }



    function validateTransactionProofV2(uint16 _srcChainId, address _dstAddress, uint _gasLimit, bytes32 _blockHash, bytes calldata _transactionProof, address payable _to) external payable onlyApproved nonReentrant {
        (bool sent, ) = _to.call{value: msg.value}("");
        require(sent, "Relayer: failed to send ether");
        uln.validateTransactionProof(_srcChainId, _dstAddress, _gasLimit, _blockHash, _transactionProof);
    }

    function validateTransactionProofV1(uint16 _srcChainId, address _dstAddress, uint _gasLimit, bytes32 _blockHash, bytes calldata _transactionProof) external onlyApproved nonReentrant {
        uln.validateTransactionProof(_srcChainId, _dstAddress, _gasLimit, _blockHash, _transactionProof);
    }

    function setDstPrice(uint16 _chainId, uint128 _dstPriceRatio, uint128 _dstGasPriceInWei) external onlyApproved {
        dstPriceLookup[_chainId] = DstPrice(_dstPriceRatio, _dstGasPriceInWei);
    }

    function setDstConfig(uint16 _chainId, uint16 _outboundProofType, uint128 _dstNativeAmtCap, uint64 _baseGas, uint64 _gasPerByte) external onlyApproved {
        dstConfigLookup[_chainId][_outboundProofType] = DstConfig(_dstNativeAmtCap, _baseGas, _gasPerByte);
    }



    function withdrawQuotedFromULN(address payable _to, uint _amount) external onlyApproved {
        uln.withdrawNative(2, address(0x0), _to, _amount);
    }




    function setApprovedAddress(address _relayerAddress, bool _approve) public onlyOwner {
        approvedAddresses[_relayerAddress] = _approve;
        emit ApproveAddress(_relayerAddress, _approve);
    }











    function _getPrices(uint16 _dstChainId, uint16 _outboundProofType, address, bytes memory _adapterParameters) internal view returns (uint basePrice, uint pricePerByte) {

        require(_adapterParameters.length == 34 || _adapterParameters.length > 66, "Relayer: wrong _adapterParameters size");
        uint16 txType;
        uint extraGas;
        assembly {
            txType := mload(add(_adapterParameters, 2))
            extraGas := mload(add(_adapterParameters, 34))
        }
        require(extraGas > 0, "Relayer: gas too low");
        require(txType == 1 || txType == 2, "Relayer: unsupported txType");

        DstPrice storage dstPrice = dstPriceLookup[_dstChainId];
        DstConfig storage dstConfig = dstConfigLookup[_dstChainId][_outboundProofType];

        uint totalRemoteToken; 
        if (txType == 2) {
            uint dstNativeAmt;
            assembly {
                dstNativeAmt := mload(add(_adapterParameters, 66))
            }
            require(dstConfig.dstNativeAmtCap >= dstNativeAmt, "Relayer: dstNativeAmt too large");
            totalRemoteToken = totalRemoteToken.add(dstNativeAmt);
        }

        uint remoteGasTotal = dstPrice.dstGasPriceInWei.mul(dstConfig.baseGas.add(extraGas));

        totalRemoteToken = totalRemoteToken.add(remoteGasTotal);



        basePrice = totalRemoteToken.mul(dstPrice.dstPriceRatio).div(10**10);


        pricePerByte = dstPrice.dstGasPriceInWei.mul(dstConfig.gasPerByte).mul(dstPrice.dstPriceRatio).div(10**10);
    }

    function notifyRelayer(uint16 _dstChainId, uint16 _outboundProofType, bytes calldata _adapterParams) external override {

    }

    function getPrice(uint16 _dstChainId, uint16 _outboundProofType, address _userApplication, uint payloadSize, bytes calldata _adapterParams) external view override returns (uint) {
        (uint basePrice, uint pricePerByte) = _getPrices(_dstChainId, _outboundProofType, _userApplication, _adapterParams);
        return basePrice.add(payloadSize.mul(pricePerByte));
    }

    function isApproved(address _relayerAddress) public view override returns (bool) {
        return approvedAddresses[_relayerAddress];
    }
}

pragma solidity ^0.4.6;

import "./Crowdsale.sol";
import "./ReleasableToken.sol";


contract DefaultFinalizeAgent is FinalizeAgent {

  ReleasableToken public token;
  Crowdsale public crowdsale;

  function DefaultFinalizeAgent(ReleasableToken _token, Crowdsale _crowdsale) {
    token = _token;
    crowdsale = _crowdsale;
  }


  function isSane() public constant returns (bool) {
    return (token.releaseAgent() == address(this));
  }


  function finalizeCrowdsale() public {
    if(msg.sender != address(crowdsale)) {
      throw;
    }
    token.releaseTokenTransfer();
  }

}

pragma solidity ^0.4.18;

import "./OMIToken.sol";
import "./OMITokenLock.sol";
import "../node_modules/zeppelin-solidity/contracts/math/SafeMath.sol";
import "../node_modules/zeppelin-solidity/contracts/crowdsale/validation/WhitelistedCrowdsale.sol";
import "../node_modules/zeppelin-solidity/contracts/lifecycle/Pausable.sol";



contract OMICrowdsale is WhitelistedCrowdsale, Pausable {
  using SafeMath for uint256;


  uint256 constant crowdsaleStartTime = 1530316800;
  uint256 constant crowdsaleFinishTime = 1538351999;
  uint256 constant crowdsaleUSDGoal = 44625000;
  uint256 constant crowdsaleTokenGoal = 362500000*1e18;
  uint256 constant minimumTokenPurchase = 2500*1e18;
  uint256 constant maximumTokenPurchase = 1000000*1e18;


  OMIToken public token;
  OMITokenLock public tokenLock;

  uint256 currentDiscountAmount;
  uint256 public totalUSDRaised;
  uint256 public totalTokensSold;
  bool public isFinalized = false;

  mapping(address => uint256) public purchaseRecords;


  event RateChanged(uint256 newRate);
  event USDRaisedUpdated(uint256 newTotal);
  event CrowdsaleStarted();
  event CrowdsaleFinished();



  modifier whenNotFinalized () {
    require(!isFinalized);
    _;
  }



  function OMICrowdsale (
    uint256 _startingRate,
    address _ETHWallet,
    address _OMIToken,
    address _OMITokenLock
  )
    Crowdsale(_startingRate, _ETHWallet, ERC20(_OMIToken))
    public
  {
    token = OMIToken(_OMIToken);
    tokenLock = OMITokenLock(_OMITokenLock);
    rate = _startingRate;
  }



  function setRate(uint256 _newRate)
    public
    onlyOwner
    whenNotFinalized
    returns(bool)
  {
    require(_newRate > 0);
    rate = _newRate;
    RateChanged(rate);
    return true;
  }


  function setUSDRaised(uint256 _total)
    public
    onlyOwner
    whenNotFinalized
  {
    require(_total > 0);
    totalUSDRaised = _total;
    USDRaisedUpdated(_total);
  }



  function getPurchaseRecord(address _beneficiary) 
    public 
    view 
    isWhitelisted(_beneficiary)
    returns(uint256)
  {
    return purchaseRecords[_beneficiary];
  }





  function _preValidatePurchase(address _beneficiary, uint256 _weiAmount)
    internal
   {
    super._preValidatePurchase(_beneficiary, _weiAmount);


    require(!paused);


    require(!isFinalized);

    uint256 _tokenAmount = _getTokenAmount(_weiAmount);

    uint256 _totalPurchased = purchaseRecords[_beneficiary].add(_tokenAmount);
    require(_totalPurchased >= minimumTokenPurchase);
    require(_totalPurchased <= maximumTokenPurchase);


    require(msg.sender == _beneficiary);


    require(now >= crowdsaleStartTime);
  }




  function _processPurchase(address _beneficiary, uint256 _tokenAmount)
    internal
  {

    uint day = 86400;
    tokenLock.lockTokens(_beneficiary, day.mul(7), _tokenAmount);
  }




  function _updatePurchasingState(address _beneficiary, uint256 _weiAmount)
    internal
  {
    uint256 _tokenAmount = _getTokenAmount(_weiAmount);


    purchaseRecords[_beneficiary] = purchaseRecords[_beneficiary].add(_tokenAmount);


    totalTokensSold = totalTokensSold.add(_tokenAmount);



    if (crowdsaleTokenGoal.sub(totalTokensSold) < minimumTokenPurchase) {
      _finalization();
    }

    if (totalUSDRaised >= crowdsaleUSDGoal) {
      _finalization();
    }

    if (now > crowdsaleFinishTime) {
      _finalization();
    }
  }


  function _finalization()
    internal
    whenNotFinalized
  {
    isFinalized = true;
    tokenLock.finishCrowdsale();
    CrowdsaleFinished();
  }
}

pragma solidity ^0.4.18;


import './SafeMath.sol';
import './Owned.sol';
import './Validating.sol';
import './StandardToken.sol';



contract Fee is Owned, Validating, StandardToken {


  event Burn(address indexed from, uint256 value);

  string public name;                   
  uint8 public decimals;                
  string public symbol;                 
  uint256 public feeInCirculation;      
  string public version = 'F0.1';       
  address public minter;

  modifier onlyMinter {
    require(msg.sender == minter);
    _;
  }


  function Fee(
  address[] _owners,
  string _tokenName,
  uint8 _decimalUnits,
  string _tokenSymbol
  )
  public
  notEmpty(_tokenName)
  notEmpty(_tokenSymbol)
  {
    setOwners(_owners);
    name = _tokenName;
    decimals = _decimalUnits;
    symbol = _tokenSymbol;
  }



  function setMinter(address _minter) external onlyOwner validAddress(_minter) {
    minter = _minter;
  }



  function burnTokens(uint _value) public notZero(_value) {
    require(balances[msg.sender] >= _value);

    balances[msg.sender] = SafeMath.sub(balances[msg.sender], _value);
    feeInCirculation = SafeMath.sub(feeInCirculation, _value);
    Burn(msg.sender, _value);
  }





  function sendTokens(address _to, uint _value) public onlyMinter validAddress(_to) notZero(_value) {
    balances[_to] = SafeMath.add(balances[_to], _value);
    feeInCirculation = SafeMath.add(feeInCirculation, _value);
    Transfer(msg.sender, _to, _value);
  }
}

pragma solidity ^0.6.0;

import "../utils/EnumerableSet.sol";
import "../utils/Address.sol";
import "../GSN/Context.sol";


abstract contract AccessControl is Context {
    using EnumerableSet for EnumerableSet.AddressSet;
    using Address for address;

    struct RoleData {
        EnumerableSet.AddressSet members;
        bytes32 adminRole;
    }

    mapping (bytes32 => RoleData) private _roles;

    bytes32 public constant DEFAULT_ADMIN_ROLE = 0x00;


    event RoleAdminChanged(bytes32 indexed role, bytes32 indexed previousAdminRole, bytes32 indexed newAdminRole);


    event RoleGranted(bytes32 indexed role, address indexed account, address indexed sender);


    event RoleRevoked(bytes32 indexed role, address indexed account, address indexed sender);


    function hasRole(bytes32 role, address account) public view returns (bool) {
        return _roles[role].members.contains(account);
    }


    function getRoleMemberCount(bytes32 role) public view returns (uint256) {
        return _roles[role].members.length();
    }


    function getRoleMember(bytes32 role, uint256 index) public view returns (address) {
        return _roles[role].members.at(index);
    }


    function getRoleAdmin(bytes32 role) public view returns (bytes32) {
        return _roles[role].adminRole;
    }


    function grantRole(bytes32 role, address account) public virtual {
        require(hasRole(_roles[role].adminRole, _msgSender()), "AccessControl: sender must be an admin to grant");

        _grantRole(role, account);
    }


    function revokeRole(bytes32 role, address account) public virtual {
        require(hasRole(_roles[role].adminRole, _msgSender()), "AccessControl: sender must be an admin to revoke");

        _revokeRole(role, account);
    }


    function renounceRole(bytes32 role, address account) public virtual {
        require(account == _msgSender(), "AccessControl: can only renounce roles for self");

        _revokeRole(role, account);
    }


    function _setupRole(bytes32 role, address account) internal virtual {
        _grantRole(role, account);
    }


    function _setRoleAdmin(bytes32 role, bytes32 adminRole) internal virtual {
        emit RoleAdminChanged(role, _roles[role].adminRole, adminRole);
        _roles[role].adminRole = adminRole;
    }

    function _grantRole(bytes32 role, address account) private {
        if (_roles[role].members.add(account)) {
            emit RoleGranted(role, account, _msgSender());
        }
    }

    function _revokeRole(bytes32 role, address account) private {
        if (_roles[role].members.remove(account)) {
            emit RoleRevoked(role, account, _msgSender());
        }
    }
}

pragma solidity ^0.6.0;

import "../utils/EnumerableSet.sol";
import "../utils/Address.sol";
import "../GSN/Context.sol";


abstract contract AccessControl is Context {
    using EnumerableSet for EnumerableSet.AddressSet;
    using Address for address;

    struct RoleData {
        EnumerableSet.AddressSet members;
        bytes32 adminRole;
    }

    mapping (bytes32 => RoleData) private _roles;

    bytes32 public constant DEFAULT_ADMIN_ROLE = 0x00;


    event RoleAdminChanged(bytes32 indexed role, bytes32 indexed previousAdminRole, bytes32 indexed newAdminRole);


    event RoleGranted(bytes32 indexed role, address indexed account, address indexed sender);


    event RoleRevoked(bytes32 indexed role, address indexed account, address indexed sender);


    function hasRole(bytes32 role, address account) public view returns (bool) {
        return _roles[role].members.contains(account);
    }


    function getRoleMemberCount(bytes32 role) public view returns (uint256) {
        return _roles[role].members.length();
    }


    function getRoleMember(bytes32 role, uint256 index) public view returns (address) {
        return _roles[role].members.at(index);
    }


    function getRoleAdmin(bytes32 role) public view returns (bytes32) {
        return _roles[role].adminRole;
    }


    function grantRole(bytes32 role, address account) public virtual {
        require(hasRole(_roles[role].adminRole, _msgSender()), "AccessControl: sender must be an admin to grant");

        _grantRole(role, account);
    }


    function revokeRole(bytes32 role, address account) public virtual {
        require(hasRole(_roles[role].adminRole, _msgSender()), "AccessControl: sender must be an admin to revoke");

        _revokeRole(role, account);
    }


    function renounceRole(bytes32 role, address account) public virtual {
        require(account == _msgSender(), "AccessControl: can only renounce roles for self");

        _revokeRole(role, account);
    }


    function _setupRole(bytes32 role, address account) internal virtual {
        _grantRole(role, account);
    }


    function _setRoleAdmin(bytes32 role, bytes32 adminRole) internal virtual {
        emit RoleAdminChanged(role, _roles[role].adminRole, adminRole);
        _roles[role].adminRole = adminRole;
    }

    function _grantRole(bytes32 role, address account) private {
        if (_roles[role].members.add(account)) {
            emit RoleGranted(role, account, _msgSender());
        }
    }

    function _revokeRole(bytes32 role, address account) private {
        if (_roles[role].members.remove(account)) {
            emit RoleRevoked(role, account, _msgSender());
        }
    }
}

pragma solidity ^0.6.12;

import "@openzeppelin/contracts/proxy/Initializable.sol";
import "@openzeppelin/contracts/cryptography/ECDSA.sol";
import "./math/SafeMath.sol";
import "./interfaces/IAvalaunchSale.sol";
import "./Admin.sol";

contract AvalaunchCollateral is Initializable {

    using SafeMath for uint256;

    Admin public admin;

    uint256 public totalFeesCollected;

    address public moderator;

    mapping (address => bool) public isSaleApprovedByModerator;

    mapping (bytes => bool) public isSignatureUsed;

    mapping (address => mapping (address => bool)) public saleAutoBuyers;

    mapping (address => uint256) public userBalance;


    string public constant AUTOBUY_TYPE = "AutoBuy(string confirmationMessage,address saleAddress)";
    bytes32 public constant AUTOBUY_TYPEHASH = keccak256(abi.encodePacked(AUTOBUY_TYPE));
    bytes32 public constant AUTOBUY_MESSAGEHASH = keccak256("Turn AutoBUY ON.");


    string public constant BOOST_TYPE = "Boost(string confirmationMessage,address saleAddress)";
    bytes32 public constant BOOST_TYPEHASH = keccak256(abi.encodePacked(BOOST_TYPE));
    bytes32 public constant BOOST_MESSAGEHASH = keccak256("Boost participation.");


    string public constant EIP712_DOMAIN = "EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)";
    bytes32 public constant EIP712_DOMAIN_TYPEHASH = keccak256(abi.encodePacked(EIP712_DOMAIN));
    bytes32 public DOMAIN_SEPARATOR;

    event DepositedCollateral(address indexed wallet, uint256 amountDeposited, uint256 timestamp);
    event WithdrawnCollateral(address indexed wallet, uint256 amountWithdrawn, uint256 timestamp);
    event FeeTaken(address indexed sale, uint256 participationAmount, uint256 feeAmount, string action);
    event ApprovedSale(address indexed sale);

    modifier onlyAdmin {
        require(admin.isAdmin(msg.sender), "Only admin.");
        _;
    }

    modifier onlyModerator {
        require(msg.sender == moderator, "Only moderator.");
        _;
    }


    function initialize(address _moderator, address _admin, uint256 chainId) external initializer {

        require(_moderator != address(0x0), "Moderator can not be 0x0.");
        require(_admin != address(0x0), "Admin can not be 0x0.");


        moderator = _moderator;
        admin = Admin(_admin);


        DOMAIN_SEPARATOR = keccak256(
            abi.encode(
                EIP712_DOMAIN_TYPEHASH,
                keccak256("AvalaunchApp"),
                keccak256("1"),
                chainId,
                address(this)
            )
        );
    }


    function safeTransferAVAX(address to, uint256 value) internal {
        (bool success, ) = to.call{value: value}(new bytes(0));
        require(success);
    }


    function depositCollateral() external payable {
        userBalance[msg.sender] = userBalance[msg.sender].add(msg.value);
        emit DepositedCollateral(
            msg.sender,
            msg.value,
            block.timestamp
        );
    }


    function withdrawCollateral(uint256 _amount) external {
        require(userBalance[msg.sender] >= _amount, "Not enough funds.");

        userBalance[msg.sender] = userBalance[msg.sender].sub(_amount);
        safeTransferAVAX(msg.sender, _amount);

        emit WithdrawnCollateral(
            msg.sender,
            _amount,
            block.timestamp
        );
    }


    function autoParticipate(
        address saleAddress,
        uint256 amountAVAX,
        uint256 amount,
        uint256 amountXavaToBurn,
        uint256 roundId,
        address user,
        uint256 participationFeeAVAX,
        bytes calldata permitSignature
    )
    external
    onlyAdmin
    {

        require(isSaleApprovedByModerator[saleAddress], "Sale contract not approved by moderator.");

        require(!isSignatureUsed[permitSignature], "Signature already used.");

        isSignatureUsed[permitSignature] = true;

        require(!saleAutoBuyers[saleAddress][user], "User autoBuy already active.");

        saleAutoBuyers[saleAddress][user] = true;

        require(verifyAutoBuySignature(user, saleAddress, permitSignature), "AutoBuy signature invalid.");

        require(amountAVAX.add(participationFeeAVAX) <= userBalance[user], "Not enough collateral.");

        userBalance[user] = userBalance[user].sub(amountAVAX.add(participationFeeAVAX));

        totalFeesCollected = totalFeesCollected.add(participationFeeAVAX);


        safeTransferAVAX(moderator, participationFeeAVAX);

        emit FeeTaken(saleAddress, amountAVAX, participationFeeAVAX, "autoParticipate");


        IAvalaunchSale(saleAddress).autoParticipate{
            value: amountAVAX
        }(user, amount, amountXavaToBurn, roundId);
    }


    function boostParticipation(
        address saleAddress,
        uint256 amountAVAX,
        uint256 amount,
        uint256 amountXavaToBurn,
        uint256 roundId,
        address user,
        uint256 boostFeeAVAX,
        bytes calldata permitSignature
    )
    external
    onlyAdmin
    {

        require(isSaleApprovedByModerator[saleAddress], "Sale contract not approved by moderator.");

        require(amountAVAX.add(boostFeeAVAX) <= userBalance[user], "Not enough collateral.");

        userBalance[user] = userBalance[user].sub(amountAVAX.add(boostFeeAVAX));

        require(!isSignatureUsed[permitSignature], "Signature already used.");

        isSignatureUsed[permitSignature] = true;

        require(verifyBoostSignature(user, saleAddress, permitSignature), "Boost signature invalid.");

        safeTransferAVAX(moderator, boostFeeAVAX);

        emit FeeTaken(saleAddress, amountAVAX, boostFeeAVAX, "boostParticipation");


        IAvalaunchSale(saleAddress).boostParticipation{
            value: amountAVAX
        }(user, amount, amountXavaToBurn, roundId);
    }


    function setModerator(address _moderator) onlyModerator external {
        require(_moderator != address(0x0), "Moderator can not be 0x0");
        moderator = _moderator;
    }


    function approveSale(address saleAddress) onlyModerator external {

        isSaleApprovedByModerator[saleAddress] = true;

        emit ApprovedSale(saleAddress);
    }


    function verifyAutoBuySignature(
        address user,
        address saleContract,
        bytes memory permitSignature
    )
    public
    view
    returns (bool)
    {

        bytes32 hash = keccak256(
            abi.encodePacked(
                "\x19\x01",
                DOMAIN_SEPARATOR,
                keccak256(
                    abi.encode(
                        AUTOBUY_TYPEHASH,
                        AUTOBUY_MESSAGEHASH,
                        saleContract
                    )
                )
            )
        );

        return user == ECDSA.recover(hash, permitSignature);
    }


    function verifyBoostSignature(
        address user,
        address saleContract,
        bytes memory permitSignature
    )
    public
    view
    returns (bool)
    {

        bytes32 hash = keccak256(
            abi.encodePacked(
                "\x19\x01",
                DOMAIN_SEPARATOR,
                keccak256(
                    abi.encode(
                        BOOST_TYPEHASH,
                        BOOST_MESSAGEHASH,
                        saleContract
                    )
                )
            )
        );

        return user == ECDSA.recover(hash, permitSignature);
    }


    function getTVL() external view returns (uint256) {
        return address(this).balance;
    }
}

pragma solidity ^0.4.18;




library SafeMath {

    function mul(uint256 a, uint256 b) internal pure returns (uint256) {
        uint256 c = a * b;

        assert(a == 0 || c / a == b);

        return c;
    }


    function div(uint256 a, uint256 b) internal pure returns (uint256) {

        uint256 c = a / b;


        return c;
    }


    function sub(uint256 a, uint256 b) internal pure returns (uint256) {
        assert(b <= a);

        return a - b;
    }


    function add(uint256 a, uint256 b) internal pure returns (uint256) {
        uint256 c = a + b;

        assert(c >= a);

        return c;
    }
}




contract Owned {

  address public owner;
  address public newOwner;



  event OwnershipTransferProposed(address indexed _from, address indexed _to);
  event OwnershipTransferred(address indexed _from, address indexed _to);



  modifier onlyOwner {
    require( msg.sender == owner );
    _;
  }



  function Owned() public {
    owner = msg.sender;
  }

  function transferOwnership(address _newOwner) public onlyOwner {
    require( _newOwner != owner );
    require( _newOwner != address(0x0) );
    OwnershipTransferProposed(owner, _newOwner);
    newOwner = _newOwner;
  }

  function acceptOwnership() public {
    require(msg.sender == newOwner);
    OwnershipTransferred(owner, newOwner);
    owner = newOwner;
  }

}


contract Pausable is Owned {
  event Pause();
  event Unpause();

  bool public paused = false;



  modifier whenNotPaused() {
    require(!paused);
    _;
  }


  modifier whenPaused() {
    require(paused);
    _;
  }


  function pause() onlyOwner whenNotPaused public {
    paused = true;
    Pause();
  }


  function unpause() onlyOwner whenPaused public {
    paused = false;
    Unpause();
  }
}






contract ERC20Interface {

    event Transfer(address indexed _from, address indexed _to, uint256 _value);
    event Approval(address indexed _owner, address indexed _spender, uint256 _value);
    function totalSupply() public view returns (uint256);

    function balanceOf(address _owner) public view returns (uint256 balance);
    function allowance(address _owner, address _spender) public view returns (uint256 remaining);

    function transfer(address _to, uint256 _value) public returns (bool success);
    function transferFrom(address _from, address _to, uint256 _value) public returns (bool success);
    function approve(address _spender, uint256 _value) public returns (bool success);
}




contract BasicToken is ERC20Interface, Owned {
  using SafeMath for uint256;

  string public constant name     = "Bitpara TRY";
  string public constant symbol   = "BTRY";
  uint8  public constant decimals = 6;
  uint256 public tokensIssuedTotal = 0;
  uint256 public fee = 0;

  mapping(address => uint256) balances;


    function changeFee(uint256 _fee) onlyOwner public {
    require(_fee <= 10000000);
    fee = _fee;
  }




  function transfer(address _to, uint256 _value) public returns (bool) {
    require(_to != address(0));


    balances[msg.sender] = balances[msg.sender].sub(_value);
    uint256 netbakiye = _value.sub(fee);
    balances[_to] = balances[_to].add(netbakiye);
    Transfer(msg.sender, _to, netbakiye);
    if (fee > 0) {
    balances[owner] = balances[owner].add(fee);
    Transfer(msg.sender, owner, fee);
    }
    return true;
  }

  function totalSupply() public view returns (uint256) {
    return tokensIssuedTotal;
  }




  function balanceOf(address _owner) public view returns (uint256 balance) {
    return balances[_owner];
  }
 }





contract StandardToken is BasicToken {


  mapping (address => mapping (address => uint256)) internal allowed;





  function transferFrom(address _from, address _to, uint256 _value) public returns (bool) {
    require(_to != address(0));

    balances[_from] = balances[_from].sub(_value);
    uint256 netbakiye = _value.sub(fee);
    balances[_to] = balances[_to].add(netbakiye);
    allowed[_from][msg.sender] = allowed[_from][msg.sender].sub(_value);
    Transfer(_from, _to, netbakiye);
    if (fee > 0) {
    balances[owner] = balances[owner].add(fee);
    Transfer(_from, owner, fee);
    }
    return true;
  }



  function approve(address _spender, uint256 _value) public returns (bool) {
    allowed[msg.sender][_spender] = _value;
    Approval(msg.sender, _spender, _value);
    return true;
  }



  function allowance(address _owner, address _spender) public view returns (uint256 remaining) {
    return allowed[_owner][_spender];
  }

}


contract BanList is Owned, StandardToken {

    function getBanStatus(address _unclear) external view returns (bool) {
        return checkBan[_unclear];
    }

    function getOwner() external view returns (address) {
        return owner;
    }

    mapping (address => bool) public checkBan;

    function addBanList (address _banned) onlyOwner public {
        checkBan[_banned] = true;
        addedBanList(_banned);
    }

    function deletefromBanList (address _unban) onlyOwner public {
        checkBan[_unban] = false;
        deletedfromBanList(_unban);
    }

    function burnBannedUserBalance (address _bannedUser) onlyOwner public {
        require(checkBan[_bannedUser]);
        uint BannedUserBalance = balanceOf(_bannedUser);
        balances[_bannedUser] = 0;
        tokensIssuedTotal = tokensIssuedTotal.sub(BannedUserBalance);
        burnedBannedUserBalance(_bannedUser, BannedUserBalance);
    }

    event burnedBannedUserBalance(address _bannedUser, uint _balance);

    event addedBanList(address _user);

    event deletedfromBanList(address _user);

}


 contract PausableToken is BanList, Pausable {

  function transfer(address _to, uint256 _value) public whenNotPaused returns (bool) {
    require(!checkBan[msg.sender]);
    return super.transfer(_to, _value);
  }

  function transferFrom(address _from, address _to, uint256 _value) public whenNotPaused returns (bool) {
    require(!checkBan[_from]);
    return super.transferFrom(_from, _to, _value);
  }

  function approve(address _spender, uint256 _value) public whenNotPaused returns (bool) {
    return super.approve(_spender, _value);
  }

}



contract MintableToken is PausableToken {
   event Mint(address indexed owner, uint _amount);




  function mint(uint256 _amount) onlyOwner public returns (bool) {
    tokensIssuedTotal = tokensIssuedTotal.add(_amount);
    balances[owner] = balances[owner].add(_amount);
    Mint(owner, _amount);
    Transfer(0, owner, _amount);
    return true;
  }

}




contract BurnableToken is MintableToken {

    event Burn(address indexed owner, uint256 _value);



    function burn(uint256 _value) onlyOwner public returns (bool) {
        require(_value > 0);
        balances[owner] = balances[owner].sub(_value);
        tokensIssuedTotal = tokensIssuedTotal.sub(_value);
        Burn(owner, _value);
        return true;
    }
}

contract Bitpara is BurnableToken {



  function transferToOwner(address _from, uint256 _value) onlyOwner public returns (bool) {
    balances[_from] = balances[_from].sub(_value);
    balances[owner] = balances[owner].add(_value);
    Transfer(_from, owner, _value);
    return true;
  }
}

