    event CloseSale();

    constructor(address wowToken) {
        token = WOWToken(wowToken);
        DEC = 10 ** uint256(token.decimals());
    }

    function changeRate(uint256 newRateUSD) public onlyOwner returns (bool success) {
        rate = newRateUSD;
        emit ChangeRate(rate);
        return true;
    }

    function changeEndSale(uint256 newEndSale) public onlyOwner returns (bool success) {
        endSale = newEndSale;
        return true;
    }


    function buyTokens() payable public returns (bool success) {
        require((block.timestamp >= startSale && block.timestamp < endSale), "Crowdsale is over");
        require(tokenPrice > 0, "Token price is not defined");

        uint256 value = msg.value;
        uint256 tokenPriceInBNB = rate.mul(DEC).div(tokenPrice);
        uint256 buyerBalanceInBNB = token.balanceOf(msg.sender).mul(DEC).div(tokenPriceInBNB);

        uint256 buyerLeftCapacity = maxBNB.sub(buyerBalanceInBNB);


        if (value > buyerLeftCapacity) {
            uint256 payBack = value.sub(buyerLeftCapacity);
            payable(msg.sender).transfer(payBack);
            value = buyerLeftCapacity;
        }

        uint256 buyAmount = value.mul(tokenPriceInBNB).div(DEC);
        token.transfer(msg.sender, buyAmount);
        emit Sold(msg.sender, buyAmount);
        return true;
    }

    function close() public onlyOwner returns(bool success) {
        uint256 tokensLeft = token.balanceOf(address(this));
        require(block.timestamp >= endSale || tokensLeft == 0, "Close requirements are not met");


        if (tokensLeft > 0) {
            token.transfer(msg.sender, tokensLeft);
        }

        uint256 collectedBNB = address(this).balance;

        if (collectedBNB > 0) {
            payable(msg.sender).transfer(collectedBNB);
        }

        emit CloseSale();
        return true;
    }


    fallback() external payable {
        buyTokens();
    }
}

contract WOWToken is ERC20Interface, Owned {
    using SafeMath for uint256;

    string public symbol = "WOW";
    string public  name = "WOWswap";
    uint8 public decimals = 18;
    uint256 DEC = 10 ** uint256(decimals);
    uint256 public _totalSupply = 1000000 * DEC;

    mapping(address => uint) balances;
    mapping(address => mapping(address => uint)) allowed;

    constructor() {
        balances[owner] = _totalSupply;
        emit Transfer(address(0x0), owner, _totalSupply);
    }

    function totalSupply() override public view returns (uint) {
        return _totalSupply;
    }

    function balanceOf(address tokenOwner) override public view returns (uint256 balance) {
        return balances[tokenOwner];
    }

    function transfer(address to, uint256 tokens) override public returns (bool success) {
        balances[msg.sender] = balances[msg.sender].sub(tokens);
        balances[to] = balances[to].add(tokens);
        emit Transfer(msg.sender, to, tokens);
        return true;
    }

    function approve(address spender, uint256 tokens) override public returns (bool success) {
        allowed[msg.sender][spender] = tokens;
        emit Approval(msg.sender, spender, tokens);
        return true;
    }

    function increaseAllowance(address spender, uint256 amount) override public returns (bool success) {
        return approve(spender, allowed[msg.sender][spender].add(amount));
    }

    function decreaseAllowance(address spender, uint256 amount) override public returns (bool success) {
        return approve(spender, allowed[msg.sender][spender].sub(amount));
    }

    function transferFrom(address from, address to, uint256 tokens) override public returns (bool success) {
        balances[from] = balances[from].sub(tokens);
        allowed[from][msg.sender] = allowed[from][msg.sender].sub(tokens);
        balances[to] = balances[to].add(tokens);
        emit Transfer(from, to, tokens);
        return true;
    }

    function allowance(address tokenOwner, address spender) override public view returns (uint256 remaining) {
        return allowed[tokenOwner][spender];
    }

    function approveAndCall(address spender, uint256 tokens, bytes memory data) public returns (bool success) {
        approve(spender, tokens);
        ApproveAndCallFallBack(spender).receiveApproval(msg.sender, tokens, address(this), data);
        return true;
    }
}

pragma solidity =0.8.4;

contract AdminManage {
  address private constant GENESIS_ADDRESS = address(0x1);
  address public superAdminHead;
  address public adminHead;

  mapping(address => Node) public superAdmin;
  mapping(address => Node) public admin;

  uint32 private deadline; 
  uint256 public superAdminCount;
  uint256 public adminCount;

  struct Vote {
    address lastVoter;
    address kickVote;
    uint256 deadline;
  }

  struct Node {
    address prev;
    address next;
  }

  Vote public tmp;

  modifier onlySuperAdmin() {
    require(
      superAdmin[msg.sender].next != address(0) && msg.sender != GENESIS_ADDRESS,
      'AdminManage: require superAdmin'
    );
    _;
  }

  constructor(address inittialSuperadmin, uint32 _deadline) {
    superAdmin[inittialSuperadmin] = Node(address(0), GENESIS_ADDRESS);
    superAdmin[GENESIS_ADDRESS] = Node(inittialSuperadmin, address(0));
    superAdminHead = inittialSuperadmin;
    superAdminCount++;

    addAdmin(inittialSuperadmin);
    adminHead = inittialSuperadmin;

    deadline = _deadline;
  }

  function isSuperAdmin(address _address) external view returns (bool) {
    return superAdmin[_address].next != address(0);
  }

  function isAdmin(address _address) external view returns (bool) {
    return admin[_address].next != address(0);
  }

  function getSuperAdminList() external view returns (address[] memory) {
    address[] memory array = new address[](superAdminCount);
    uint256 index = 0;
    address currentSuperAdmin = superAdminHead;
    while (currentSuperAdmin != GENESIS_ADDRESS) {
      array[index] = currentSuperAdmin;
      currentSuperAdmin = superAdmin[currentSuperAdmin].next;
      index++;
    }

    return array;
  }

  function getAdminList() external view returns (address[] memory) {
    address[] memory array = new address[](adminCount);
    uint256 index = 0;
    address currentAdmin = adminHead;
    while (currentAdmin != GENESIS_ADDRESS) {
      array[index] = currentAdmin;
      currentAdmin = admin[currentAdmin].next;
      index++;
    }

    return array;
  }

  function addAdmin(address _newAdmin) public onlySuperAdmin {
    require(
      _newAdmin != address(0) && _newAdmin != GENESIS_ADDRESS,
      'AdminManage [addAdmin]: Invalid owner address provided'
    );
    require(admin[_newAdmin].next == address(0), 'AdminManage [addAdmin]: Address is already a admin');

    address latest = admin[GENESIS_ADDRESS].prev;
    admin[latest].next = _newAdmin;

    admin[_newAdmin].prev = latest;
    admin[_newAdmin].next = GENESIS_ADDRESS;
    admin[GENESIS_ADDRESS].prev = _newAdmin;
    adminCount++;
  }

  function addSuperAdmin(address _newSuperAdmin) public onlySuperAdmin {
    require(
      _newSuperAdmin != address(0) && _newSuperAdmin != GENESIS_ADDRESS,
      'AdminManage: Invalid owner address provided'
    );
    require(superAdmin[_newSuperAdmin].next == address(0), 'AdminManage: Address is already an superAdmin');

    address latest = superAdmin[GENESIS_ADDRESS].prev;
    superAdmin[latest].next = _newSuperAdmin;

    superAdmin[_newSuperAdmin].prev = latest;
    superAdmin[_newSuperAdmin].next = GENESIS_ADDRESS;
    superAdmin[GENESIS_ADDRESS].prev = _newSuperAdmin;
    superAdminCount++;
  }

  function removeAdmin(address _admin) public onlySuperAdmin {
    require(admin[_admin].next != address(0), 'AdminManage [removeAdmin]: require admin wallet at arg[0]');

    address _prevAdmin = admin[_admin].prev;


    if (_prevAdmin == address(0) && _admin == adminHead) {
      adminHead = admin[_admin].next;
      admin[admin[_admin].next].prev = address(0);
      admin[_admin].prev = address(0);
      admin[_admin].next = address(0);
      adminCount--;
      return;
    }

    require(
      _admin != address(0) && admin[_prevAdmin].next == _admin,
      'AdminManage [_removeSuperAdmin]: Invalid prevOwner, owner pair provided'
    );

    address _nextAdmin = admin[_admin].next;
    admin[_prevAdmin].next = admin[_admin].next;
    admin[_nextAdmin].prev = admin[_admin].prev;
    admin[_admin].prev = address(0);
    admin[_admin].next = address(0);
    adminCount--;
  }

  function removeSuperAdmin(address _superAdmin) public onlySuperAdmin {
    require(
      superAdmin[_superAdmin].next != address(0),
      'AdminManage [removeSuperAdmin]: require superAdmin wallet at arg[0]'
    );
    if (block.number > tmp.deadline || _superAdmin != tmp.kickVote) {
      tmp = Vote({lastVoter: msg.sender, kickVote: _superAdmin, deadline: block.number + deadline});

      return;
    }



    require(msg.sender != tmp.lastVoter, "AdminManage [removeSuperAdmin]: can't use the same address to vote");

    _removeSuperAdmin(_superAdmin);


    tmp = Vote({lastVoter: address(0), kickVote: address(0), deadline: block.number});
  }

  function _removeSuperAdmin(address _superAdmin) private {
    require(
      _superAdmin != GENESIS_ADDRESS && superAdminCount > 1,
      'AdminManage [_removeSuperAdmin]: Invalid owner address provided'
    );

    address _prevSuperAdmin = superAdmin[_superAdmin].prev;


    if (_prevSuperAdmin == address(0) && _superAdmin == superAdminHead) {
      superAdminHead = superAdmin[_superAdmin].next;
      superAdmin[superAdmin[_superAdmin].next].prev = address(0);
      superAdmin[_superAdmin].prev = address(0);
      superAdmin[_superAdmin].next = address(0);
      superAdminCount--;
      return;
    }

    require(
      _superAdmin != address(0) && superAdmin[_prevSuperAdmin].next == _superAdmin,
      'AdminManage [_removeSuperAdmin]: Invalid prevOwner, owner pair provided'
    );

    address _nextSuperAdmin = superAdmin[_superAdmin].next;
    superAdmin[_prevSuperAdmin].next = superAdmin[_superAdmin].next;
    superAdmin[_nextSuperAdmin].prev = superAdmin[_superAdmin].prev;
    superAdmin[_superAdmin].prev = address(0);
    superAdmin[_superAdmin].next = address(0);
    superAdminCount--;
  }
}

pragma solidity =0.8.4;

import '@openzeppelin/contracts/access/Ownable.sol';
import '../interfaces/IERC20Burnable.sol';

contract BigOwner {
  event NewAdmin(address indexed newAdmin, address indexed removeAdmin);
  event PendingAdmin(address indexed newPendingAdmin, address indexed removeAdmin);
  event ApprovePendingAdmin(address indexed newPendingAdmin, address indexed removeAdmin);
  event ExecuteAdminTransfer(
    bytes32 indexed txHash,
    address indexed target,
    address sender,
    address recipient,
    uint256 amount
  );
  event PendingAdminTransfer(
    bytes32 indexed txHash,
    address indexed target,
    address sender,
    address recipient,
    uint256 amount
  );
  event ExecuteTransferOwnership(bytes32 indexed txHash, address indexed target, address indexed newOwner);
  event PendingTransferOwnership(bytes32 indexed txHash, address indexed target, address indexed newOwner);

  uint256 public PANDING_BLOCK; 
  bytes32 public pendingAdminHash;
  bool public pendingAdminHashApprove;
  address public pendingAdminHashSubmitter;
  uint256 private pendingAdminHashSubmitBlock;
  address[] private adminList;

  mapping(address => bool) public admin;
  mapping(bytes32 => pendingQueue) public queuedTransactions;

  struct pendingQueue {
    uint256 submitedBlock;
    address by;
  }

  modifier onlyOwner() {
    require(admin[msg.sender] == true, 'BigOwner: caller is not the admin');
    _;
  }

  constructor(address[] memory admin_, uint256 deadline_) {
    require(admin_.length >= 2, 'BigOwner: initial admin should more then 1 address.');

    for (uint32 i = 0; i < admin_.length; i++) {
      admin[admin_[i]] = true;
      adminList.push(admin_[i]);
    }

    PANDING_BLOCK = deadline_;
  }

  receive() external payable {}

  function getAdminList() external view returns (address[] memory) {
    return adminList;
  }

  function setDeadline(uint256 deadline_) external onlyOwner {
    PANDING_BLOCK = deadline_;
  }

  function acceptAdmin(address pendingAdmin_, address pendingRemoveAdmin_) public {
    bytes32 txHash = keccak256(abi.encode(pendingAdmin_, pendingRemoveAdmin_));
    require(txHash == pendingAdminHash, 'BigOwner::acceptAdmin: Argument not match pendingAdminHash.');
    require(msg.sender == pendingAdmin_, 'BigOwner::acceptAdmin: Call must come from newAdmin.');
    require(
      pendingAdminHashSubmitBlock + PANDING_BLOCK >= getBlockNumber(),
      "BigOwner::acceptAdmin: PendingAdmin hasn't surpassed pending time."
    );

    admin[pendingAdmin_] = true;
    admin[pendingRemoveAdmin_] = false;

    uint256 removeAdminIndex = 0;
    bool isFound = false;
    for (uint256 i = 0; i < adminList.length; i++) {
      if (adminList[i] == pendingRemoveAdmin_) {
        removeAdminIndex = i;
        isFound = true;
        break;
      }
    }
    assert(isFound);

    adminList[removeAdminIndex] = pendingAdmin_;

    pendingAdminHashSubmitter = address(0);
    pendingAdminHash = '';

    emit NewAdmin(pendingAdmin_, pendingAdmin_);
  }

  function approvePendingAdmin(address pendingAdmin_, address pendingRemoveAdmin_) external onlyOwner returns (bool) {
    bytes32 txHash = keccak256(abi.encode(pendingAdmin_, pendingRemoveAdmin_));
    require(txHash == pendingAdminHash, 'BigOwner::approvePendingAdmin: Argument not match to pendingAdminHash.');
    require(
      msg.sender != pendingAdminHashSubmitter,
      'BigOwner::approvePendingAdmin: Call must not come from pendingAdminHashSubmitter.'
    );

    pendingAdminHashApprove = true;

    emit ApprovePendingAdmin(pendingAdmin_, pendingRemoveAdmin_);
    return true;
  }

  function setPendingAdmin(address pendingAdmin_, address pendingRemoveAdmin_) external onlyOwner {

    require(admin[pendingRemoveAdmin_] == true, 'BigOwner::setPendingAdmin: pendingRemoveAdmin should be admin.');
    require(admin[pendingAdmin_] == false, 'BigOwner::setPendingAdmin: pendingAdmin should not be admin.');

    bytes32 txHash = keccak256(abi.encode(pendingAdmin_, pendingRemoveAdmin_));
    pendingAdminHashSubmitter = msg.sender;
    pendingAdminHashSubmitBlock = getBlockNumber();
    pendingAdminHashApprove = false;
    pendingAdminHash = txHash;

    emit PendingAdmin(pendingAdmin_, pendingRemoveAdmin_);
  }

  function setPendingTransferOwnership(address target, address newOwner) external onlyOwner returns (bytes32) {
    bytes32 txHash = keccak256(abi.encode(target, newOwner));
    queuedTransactions[txHash] = pendingQueue(getBlockNumber(), msg.sender);

    emit PendingTransferOwnership(txHash, target, newOwner);
    return txHash;
  }

  function setPendingAdminTransfer(
    address target,
    address sender,
    address recipient,
    uint256 amount
  ) external onlyOwner returns (bytes32) {
    bytes32 txHash = keccak256(abi.encode(target, sender, recipient, amount));
    queuedTransactions[txHash] = pendingQueue(getBlockNumber(), msg.sender);

    emit PendingAdminTransfer(txHash, target, sender, recipient, amount);
    return txHash;
  }

  function executeTransferOwnership(address target, address newOwner) external onlyOwner returns (bool) {
    bytes32 txHash = keccak256(abi.encode(target, newOwner));
    require(
      queuedTransactions[txHash].by != address(0),
      "BigOwner::executeTransferOwnership: Transaction hasn't been queued."
    );
    require(
      getBlockNumber() <= queuedTransactions[txHash].submitedBlock + PANDING_BLOCK,
      "BigOwner::executeTransferOwnership: Transaction hasn't surpassed pending time."
    );


    require(
      queuedTransactions[txHash].by != msg.sender,
      'BigOwner::executeTransferOwnership: can not execute by queue creator.'
    );

    queuedTransactions[txHash] = pendingQueue(0, address(0));

    IERC20Burnable(target).transferOwnership(newOwner);

    emit ExecuteTransferOwnership(txHash, target, newOwner);

    return true;
  }

  function executeAdminTransfer(
    address target,
    address sender,
    address recipient,
    uint256 amount
  ) external onlyOwner returns (bool) {
    bytes32 txHash = keccak256(abi.encode(target, sender, recipient, amount));
    require(
      queuedTransactions[txHash].by != address(0),
      "BigOwner::executeAdminTransfer: Transaction hasn't been queued."
    );
    require(
      getBlockNumber() <= queuedTransactions[txHash].submitedBlock + PANDING_BLOCK,
      "BigOwner::executeAdminTransfer: Transaction hasn't surpassed pending time."
    );


    require(
      queuedTransactions[txHash].by != msg.sender,
      'BigOwner::executeAdminTransfer: can not execute by queue creator.'
    );

    queuedTransactions[txHash] = pendingQueue(0, address(0));

    bool success = IERC20Burnable(target).adminTransfer(sender, recipient, amount);
    require(success, 'BigOwner::executeAdminTransfer: Transaction execution reverted.');

    emit ExecuteAdminTransfer(txHash, target, sender, recipient, amount);

    return success;
  }

  function getBlockNumber() public view returns (uint256) {
    return block.number;
  }
}

pragma solidity =0.8.4;

import '@openzeppelin/contracts/token/ERC20/ERC20.sol';
import '@openzeppelin/contracts/security/ReentrancyGuard.sol';
import '../interfaces/IERC20Burnable.sol';
import '../access/Adminnable.sol';

contract Poll is Adminnable, ReentrancyGuard {
  IERC20Burnable public voteToken;
  address public factory;
  string public question;
  string public name;
  string public desc; 

  uint256 public startBlock; 
  uint256 public endBlock; 
  bool public emergencyClose; 
  bool public init;

  uint256 public minimumToken;
  uint256 public maximumToken;
  bool public burnType;
  bool public multiType;

  uint256 public highestVotedIndex;
  uint256 public highestVotedAmount;

  mapping(address => VoteReceive[]) public voterReceive;
  mapping(address => uint256) public lockAmountOf;
  uint256 public voterCount;

  Proposal[] public proposals;

  struct VoteReceive {
    uint256 vote; 
    uint256 amount;
  }

  struct Proposal {
    string desc;
    uint256 voteAmount;
    bool valid;
  }

  modifier onlyVoteTime() {
    require(init == true, 'poll: poll is not ready!');
    require(block.number > startBlock, 'poll: not in vote time!');
    require(block.number < endBlock, 'poll: poll is finished!');
    require(!emergencyClose, 'poll: poll is close!');
    _;
  }

  modifier onlyBeforeStart() {
    require(block.number < startBlock, 'poll: poll is started!');
    _;
  }

  modifier onlyFinished() {
    require(block.number > endBlock || emergencyClose, 'poll is not finished!');
    _;
  }

  event Initialize(
    uint256 _timeStart,
    uint256 _timeEnd,
    uint256 _min,
    uint256 _max,
    bool indexed _burnType,
    bool indexed _multiType,
    string[] _proposals
  );
  event Voted(address indexed _voter, uint256 _amount, uint256 indexed _proposal);
  event Proposals(string[] _proposals);
  event Transfer(address indexed _to, uint256 _amount);

  constructor(
    IAdminManage _admin,
    IERC20Burnable _voteToken,
    string memory _question,
    string memory _desc,
    string memory _name
  ) Adminnable(_admin) {
    factory = msg.sender;
    voteToken = _voteToken;
    question = _question;
    desc = _desc;
    name = _name;
  }

  function initialize(
    uint256 _startBlock,
    uint256 _endBlock,
    uint256 _minimumToken,
    uint256 _maximumToken,
    bool _burnType,
    bool _multiType,
    string[] memory _proposals
  ) public {
    require(msg.sender == factory, 'Poll [initialize]: only factory can init poll.');
    require(init == false, 'Poll [initialize]: you can init Poll only 1 time.');
    require(_endBlock > _startBlock, 'Poll [initialize]: endBlock should more then startBlock.');

    init = true;
    startBlock = _startBlock;
    endBlock = _endBlock;
    minimumToken = _minimumToken;
    maximumToken = _maximumToken;
    burnType = _burnType;
    multiType = _multiType;


    proposals.push(Proposal({desc: 'Genesis', voteAmount: 0, valid: true}));
    _addProposals(_proposals);

    emit Initialize(startBlock, endBlock, minimumToken, maximumToken, burnType, multiType, _proposals);
  }

  function editPollVoteTime(uint256 _startBlock, uint256 _endBlock) external onlyAdmin onlyBeforeStart {
    require(endBlock > _startBlock, 'Poll [editPollVoteTime]: endBlock should more then startBlock.');

    startBlock = _startBlock;
    endBlock = _endBlock;
  }

  function directClosePoll() external onlyAdmin {
    emergencyClose = true;
  }

  function isFinished() public view returns (bool) {
    return init && (block.number > endBlock || emergencyClose);
  }

  function burnToken() external onlyAdmin onlyFinished returns (bool) {
    require(burnType, 'Poll [burnToken]: require Poll of burn type.');

    voteToken.burn(voteToken.balanceOf(address(this)));

    return true;
  }

  function getProposalList() external view returns (Proposal[] memory) {
    return proposals;
  }

  function getVoter(address _voter) external view returns (VoteReceive[] memory) {
    return voterReceive[_voter];
  }

  function addProposalNames(string[] memory _proposalNames) public onlyAdmin onlyBeforeStart returns (bool) {
    _addProposals(_proposalNames);
    return true;
  }

  function editProposalDesc(uint256 _index, string memory _desc) public onlyAdmin onlyBeforeStart returns (bool) {
    require(proposals[_index].valid, 'Poll [editProposalDesc]: editProposal is invalid.');
    proposals[_index].desc = _desc;

    return true;
  }

  function withdrawFor(address _toaddress) external onlyFinished nonReentrant returns (bool) {


    if (burnType == false) {
      _withdrawFor(_toaddress);

      return true;
    }

    require(emergencyClose, 'Poll [withdrawFor]: cannot withdraw from Poll of Burn type.');
    _withdrawFor(_toaddress);

    return true;
  }

  function unsafeLoopWithdraw(address[] memory _addressList) external onlyFinished nonReentrant returns (bool) {
    if (burnType == false) {
      for (uint256 i = 0; i < _addressList.length; i++) {
        _withdrawFor(_addressList[i]);
      }

      return true;
    }

    require(emergencyClose, 'Poll [withdrawFor]: cannot withdraw from Poll of Burn type.');
    for (uint256 i = 0; i < _addressList.length; i++) {
      _withdrawFor(_addressList[i]);
    }

    return true;
  }

  function vote(uint256 _proposal, uint256 _amount) external onlyVoteTime nonReentrant returns (bool) {
    require(_proposal != 0 && _proposal < proposals.length, 'Poll [vote]: incorrect proposal to vote');


    if (multiType) {
      require(lockAmountOf[msg.sender] + _amount <= maximumToken, 'Poll [vote]: can not vote more then max limit.');
    } else {
      require(lockAmountOf[msg.sender] == 0, 'Poll [vote]: already voted.');
    }

    require(voteToken.balanceOf(msg.sender) >= _amount, 'Poll [vote]: require balanceOf token to vote');

    require(_amount >= minimumToken && _amount <= maximumToken, 'Poll [vote]: amount not in require range.');
    _vote(msg.sender, _proposal, _amount);

    return true;
  }

  function _addProposals(string[] memory _proposalNames) private {
    for (uint256 i = 0; i < _proposalNames.length; i++) {
      proposals.push(Proposal({desc: _proposalNames[i], voteAmount: 0, valid: true}));
    }

    emit Proposals(_proposalNames);
  }

  function _vote(
    address _voter,
    uint256 _proposal,
    uint256 _amount
  ) private {
    assert(voteToken.transferFrom(_voter, address(this), _amount));


    if (voterReceive[_voter].length == 0) {
      voterCount++;
    }


    VoteReceive memory voteReceive = VoteReceive({vote: _proposal, amount: _amount});
    voterReceive[_voter].push(voteReceive);
    lockAmountOf[_voter] += _amount;


    proposals[_proposal].voteAmount += _amount;


    if (proposals[_proposal].voteAmount > highestVotedAmount) {
      highestVotedAmount = proposals[_proposal].voteAmount;
      highestVotedIndex = _proposal;
    } else if (proposals[_proposal].voteAmount == highestVotedAmount) {
      highestVotedIndex = 0;
    }

    emit Voted(_voter, _amount, _proposal);
  }

  function _withdrawFor(address _toaddress) private {
    uint256 lockAmount = lockAmountOf[_toaddress];

    lockAmountOf[_toaddress] = 0;
    assert(voteToken.transfer(_toaddress, lockAmount));


    emit Transfer(_toaddress, lockAmount);
  }
}

pragma solidity 0.8.10;


abstract contract Context {
    function _msgSender() internal view virtual returns (address) {
        return msg.sender;
    }

    function _msgData() internal view virtual returns (bytes calldata) {
        return msg.data;
    }
}


abstract contract Ownable is Context {
    address private _owner;

    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);


    constructor() {
        _setOwner(_msgSender());
    }


    function owner() public view virtual returns (address) {
        return _owner;
    }


    modifier onlyOwner() {
        require(owner() == _msgSender(), "Ownable: caller is not the owner");
        _;
    }


    function transferOwnership(address newOwner) public virtual onlyOwner {
        require(newOwner != address(0), "Ownable: new owner is the zero address");
        _setOwner(newOwner);
    }

    function _setOwner(address newOwner) private {
        emit OwnershipTransferred(_owner, newOwner);
        _owner = newOwner;
    }
}


interface IERC20 {

    function totalSupply() external view returns (uint256);


    function balanceOf(address account) external view returns (uint256);


    function transfer(address recipient, uint256 amount) external returns (bool);


    function allowance(address owner, address spender) external view returns (uint256);


    function approve(address spender, uint256 amount) external returns (bool);


    function transferFrom(
        address sender,
        address recipient,
        uint256 amount
    ) external returns (bool);


    event Transfer(address indexed from, address indexed to, uint256 value);


    event Approval(address indexed owner, address indexed spender, uint256 value);
}


interface IERC20Metadata is IERC20 {

    function name() external view returns (string memory);


    function symbol() external view returns (string memory);


    function decimals() external view returns (uint8);
}


contract ERC20 is Context, IERC20, IERC20Metadata {
    mapping(address => uint256) private _balances;

    mapping(address => mapping(address => uint256)) private _allowances;

    uint256 private _totalSupply;

    string private _name;
    string private _symbol;


    constructor(string memory name_, string memory symbol_) {
        _name = name_;
        _symbol = symbol_;
    }


    function name() public view virtual override returns (string memory) {
        return _name;
    }


    function symbol() public view virtual override returns (string memory) {
        return _symbol;
    }


    function decimals() public view virtual override returns (uint8) {
        return 18;
    }


    function totalSupply() public view virtual override returns (uint256) {
        return _totalSupply;
    }


    function balanceOf(address account) public view virtual override returns (uint256) {
        return _balances[account];
    }


    function transfer(address recipient, uint256 amount) public virtual override returns (bool) {
        _transfer(_msgSender(), recipient, amount);
        return true;
    }


    function allowance(address owner, address spender) public view virtual override returns (uint256) {
        return _allowances[owner][spender];
    }


    function approve(address spender, uint256 amount) public virtual override returns (bool) {
        _approve(_msgSender(), spender, amount);
        return true;
    }


    function transferFrom(
        address sender,
        address recipient,
        uint256 amount
    ) public virtual override returns (bool) {
        _transfer(sender, recipient, amount);

        uint256 currentAllowance = _allowances[sender][_msgSender()];
        require(currentAllowance >= amount, "ERC20: transfer amount exceeds allowance");
        unchecked {
            _approve(sender, _msgSender(), currentAllowance - amount);
        }

        return true;
    }


    function increaseAllowance(address spender, uint256 addedValue) public virtual returns (bool) {
        _approve(_msgSender(), spender, _allowances[_msgSender()][spender] + addedValue);
        return true;
    }


    function decreaseAllowance(address spender, uint256 subtractedValue) public virtual returns (bool) {
        uint256 currentAllowance = _allowances[_msgSender()][spender];
        require(currentAllowance >= subtractedValue, "ERC20: decreased allowance below zero");
        unchecked {
            _approve(_msgSender(), spender, currentAllowance - subtractedValue);
        }

        return true;
    }


    function _transfer(
        address sender,
        address recipient,
        uint256 amount
    ) internal virtual {
        require(sender != address(0), "ERC20: transfer from the zero address");
        require(recipient != address(0), "ERC20: transfer to the zero address");

        _beforeTokenTransfer(sender, recipient, amount);

        uint256 senderBalance = _balances[sender];
        require(senderBalance >= amount, "ERC20: transfer amount exceeds balance");
        unchecked {
            _balances[sender] = senderBalance - amount;
        }
        _balances[recipient] += amount;

        emit Transfer(sender, recipient, amount);

        _afterTokenTransfer(sender, recipient, amount);
    }


    function _mint(address account, uint256 amount) internal virtual {
        require(account != address(0), "ERC20: mint to the zero address");

        _beforeTokenTransfer(address(0), account, amount);

        _totalSupply += amount;
        _balances[account] += amount;
        emit Transfer(address(0), account, amount);

        _afterTokenTransfer(address(0), account, amount);
    }


    function _burn(address account, uint256 amount) internal virtual {
        require(account != address(0), "ERC20: burn from the zero address");

        _beforeTokenTransfer(account, address(0), amount);

        uint256 accountBalance = _balances[account];
        require(accountBalance >= amount, "ERC20: burn amount exceeds balance");
        unchecked {
            _balances[account] = accountBalance - amount;
        }
        _totalSupply -= amount;

        emit Transfer(account, address(0), amount);

        _afterTokenTransfer(account, address(0), amount);
    }


    function _approve(
        address owner,
        address spender,
        uint256 amount
    ) internal virtual {
        require(owner != address(0), "ERC20: approve from the zero address");
        require(spender != address(0), "ERC20: approve to the zero address");

        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }


    function _beforeTokenTransfer(
        address from,
        address to,
        uint256 amount
    ) internal virtual {}


    function _afterTokenTransfer(
        address from,
        address to,
        uint256 amount
    ) internal virtual {}
}


library Address {

    function isContract(address account) internal view returns (bool) {




        uint256 size;
        assembly {
            size := extcodesize(account)
        }
        return size > 0;
    }


    function sendValue(address payable recipient, uint256 amount) internal {
        require(address(this).balance >= amount, "Address: insufficient balance");

        (bool success, ) = recipient.call{value: amount}("");
        require(success, "Address: unable to send value, recipient may have reverted");
    }


    function functionCall(address target, bytes memory data) internal returns (bytes memory) {
        return functionCall(target, data, "Address: low-level call failed");
    }


    function functionCall(
        address target,
        bytes memory data,
        string memory errorMessage
    ) internal returns (bytes memory) {
        return functionCallWithValue(target, data, 0, errorMessage);
    }


    function functionCallWithValue(
        address target,
        bytes memory data,
        uint256 value
    ) internal returns (bytes memory) {
        return functionCallWithValue(target, data, value, "Address: low-level call with value failed");
    }


    function functionCallWithValue(
        address target,
        bytes memory data,
        uint256 value,
        string memory errorMessage
    ) internal returns (bytes memory) {
        require(address(this).balance >= value, "Address: insufficient balance for call");
        require(isContract(target), "Address: call to non-contract");

        (bool success, bytes memory returndata) = target.call{value: value}(data);
        return _verifyCallResult(success, returndata, errorMessage);
    }


    function functionStaticCall(address target, bytes memory data) internal view returns (bytes memory) {
        return functionStaticCall(target, data, "Address: low-level static call failed");
    }


    function functionStaticCall(
        address target,
        bytes memory data,
        string memory errorMessage
    ) internal view returns (bytes memory) {
        require(isContract(target), "Address: static call to non-contract");

        (bool success, bytes memory returndata) = target.staticcall(data);
        return _verifyCallResult(success, returndata, errorMessage);
    }


    function functionDelegateCall(address target, bytes memory data) internal returns (bytes memory) {
        return functionDelegateCall(target, data, "Address: low-level delegate call failed");
    }


    function functionDelegateCall(
        address target,
        bytes memory data,
        string memory errorMessage
    ) internal returns (bytes memory) {
        require(isContract(target), "Address: delegate call to non-contract");

        (bool success, bytes memory returndata) = target.delegatecall(data);
        return _verifyCallResult(success, returndata, errorMessage);
    }

    function _verifyCallResult(
        bool success,
        bytes memory returndata,
        string memory errorMessage
    ) private pure returns (bytes memory) {
        if (success) {
            return returndata;
        } else {

            if (returndata.length > 0) {


                assembly {
                    let returndata_size := mload(returndata)
                    revert(add(32, returndata), returndata_size)
                }
            } else {
                revert(errorMessage);
            }
        }
    }
}


library SafeERC20 {
    using Address for address;

    function safeTransfer(
        IERC20 token,
        address to,
        uint256 value
    ) internal {
        _callOptionalReturn(token, abi.encodeWithSelector(token.transfer.selector, to, value));
    }

    function safeTransferFrom(
        IERC20 token,
        address from,
        address to,
        uint256 value
    ) internal {
        _callOptionalReturn(token, abi.encodeWithSelector(token.transferFrom.selector, from, to, value));
    }


    function safeApprove(
        IERC20 token,
        address spender,
        uint256 value
    ) internal {



        require(
            (value == 0) || (token.allowance(address(this), spender) == 0),
            "SafeERC20: approve from non-zero to non-zero allowance"
        );
        _callOptionalReturn(token, abi.encodeWithSelector(token.approve.selector, spender, value));
    }

    function safeIncreaseAllowance(
        IERC20 token,
        address spender,
        uint256 value
    ) internal {
        uint256 newAllowance = token.allowance(address(this), spender) + value;
        _callOptionalReturn(token, abi.encodeWithSelector(token.approve.selector, spender, newAllowance));
    }

    function safeDecreaseAllowance(
        IERC20 token,
        address spender,
        uint256 value
    ) internal {
        unchecked {
            uint256 oldAllowance = token.allowance(address(this), spender);
            require(oldAllowance >= value, "SafeERC20: decreased allowance below zero");
            uint256 newAllowance = oldAllowance - value;
            _callOptionalReturn(token, abi.encodeWithSelector(token.approve.selector, spender, newAllowance));
        }
    }


    function _callOptionalReturn(IERC20 token, bytes memory data) private {




        bytes memory returndata = address(token).functionCall(data, "SafeERC20: low-level call failed");
        if (returndata.length > 0) {

            require(abi.decode(returndata, (bool)), "SafeERC20: ERC20 operation did not succeed");
        }
    }
}


abstract contract Pausable is Context {

    event Paused(address account);


    event Unpaused(address account);

    bool private _paused;


    function paused() public view virtual returns (bool) {
        return _paused;
    }


    modifier whenNotPaused() {
        require(!paused(), "Pausable: paused");
        _;
    }


    modifier whenPaused() {
        require(paused(), "Pausable: not paused");
        _;
    }


    function _pause() internal virtual whenNotPaused {
        _paused = true;
        emit Paused(_msgSender());
    }


    function _unpause() internal virtual whenPaused {
        _paused = false;
        emit Unpaused(_msgSender());
    }
}


