library SafeMath {
	function add(uint256 a, uint256 b) internal constant returns (uint256) {
		uint256 c = a + b;
		assert(c >= a && c >= b);
		return c;
	}

	function sub(uint256 a, uint256 b) internal constant returns (uint256) {
		assert(b <= a);
		return a - b;
	}
}


contract MerchantSubscription {
	struct Status {
	bool isActive;
	bool isClosed;
	bool isPaused;
	}



	address public merchant;

	address public owner;

	address public pendingOwner;

	Status public status = Status(false, false, false);

	uint public amount = 0;

	string public name;

	string public version = '1.0.3';




	event SubscriptionPaymentMade(address customer, uint amount);

	event WithdrawalMade(address merchant, address owner, uint amount);

	event OwnerChanged(address to);

	event SubscriptionPaused();

	event SubscriptionResumed();

	event SubscriptionClosed();

	event SubscriptionActivated();



	modifier onlyOwner {
		require(msg.sender == owner);
		_;
	}

	modifier onlyPendingOwner {
		require(msg.sender == pendingOwner);
		_;
	}

	modifier onlyMerchant {
		require(msg.sender == merchant);
		_;
	}

	modifier allowDeposit {
		require(!status.isClosed && !status.isPaused && status.isActive);
		_;
	}




	function MerchantSubscription(address _merchant, string _name) {
		merchant = _merchant;
		owner = msg.sender;
		name = _name;
	}


	function() allowDeposit payable {
		amount = SafeMath.add(amount, msg.value);

		SubscriptionPaymentMade(msg.sender, msg.value);
	}

	function withdrawal(uint withdrawalAmount) onlyOwner public {
		require(withdrawalAmount <= amount);

		amount = SafeMath.sub(amount, withdrawalAmount);

		merchant.transfer(withdrawalAmount);

		WithdrawalMade(merchant, owner, withdrawalAmount);
	}

	function activate() onlyMerchant public {
		require(!status.isActive);

		status.isActive = true;

		SubscriptionActivated();
	}

	function pause() onlyOwner public {
		require(!status.isPaused);

		status.isPaused = true;

		SubscriptionPaused();
	}

	function resume() onlyOwner public {
		require(status.isPaused);

		status.isPaused = false;

		SubscriptionResumed();
	}

	function close() onlyOwner public {
		require(!status.isClosed);

		status.isClosed = true;

		SubscriptionClosed();
	}

	function transferOwnership(address newOwner) onlyOwner public {
		require(newOwner != owner);

		pendingOwner = newOwner;
	}

	function claimOwnership() onlyPendingOwner {
		owner = pendingOwner;
		pendingOwner = 0x0;

		OwnerChanged(owner);
	}
}

pragma solidity ^0.4.7;



contract Fundraiser {



    uint public constant dust = 1 finney; 





    address public admin;
    address public treasury;


    uint public beginBlock;
    uint public endBlock;



    uint public atomRate; 


    bool public isHalted = false;






    mapping (address => uint) public record;
    mapping (address => address) public returnAddresses;


    uint public totalEther = 0;

    uint public totalAtom = 0;





    function Fundraiser(address _admin, address _treasury, uint _beginBlock, uint _endBlock, uint _atomRate) {
        admin = _admin;
        treasury = _treasury;
        beginBlock = _beginBlock;
        endBlock = _endBlock;
	atomRate = _atomRate;
    }


    modifier only_admin { if (msg.sender != admin) throw; _; }

    modifier only_before_period { if (block.number >= beginBlock) throw; _; }

    modifier only_during_period { if (block.number < beginBlock || block.number >= endBlock || isHalted) throw; _; }

    modifier only_during_halted_period { if (block.number < beginBlock || block.number >= endBlock || !isHalted) throw; _; }

    modifier only_after_period { if (block.number < endBlock) throw; _; }

    modifier is_not_dust { if (msg.value < dust) throw; _; }


    event Received(address indexed recipient, uint amount, uint currentRate);

    event Halted();

    event Unhalted();


    function() {
	throw;
    }



    function donate(address _donor, address _returnAddress, bytes32 checksum) payable only_during_period is_not_dust {

	if (!(sha3(bytes32(_donor)^bytes32(_returnAddress)) == checksum)) throw;



        if (!treasury.call.value(msg.value)()) throw;


	var atoms = msg.value * atomRate;


        record[_donor] += atoms;
        returnAddresses[_donor] = _returnAddress; 


        totalEther += msg.value;
	totalAtom += atoms;

        Received(_donor, msg.value, atomRate);
    }



    function adjustRate(uint newRate) only_admin only_during_period {
	atomRate = newRate;
    }


    function halt() only_admin only_during_period {
        isHalted = true;
        Halted();
    }


    function unhalt() only_admin only_during_halted_period {
        isHalted = false;
        Unhalted();
    }


    function kill() only_admin only_after_period {
        suicide(treasury);
    }
}

pragma solidity ^0.4.0;


contract ProjectKudos {


    uint KUDOS_LIMIT_JUDGE = 1000;


    uint KUDOS_LIMIT_USER  = 10;



    enum GrantReason {
        Facebook,
        Twitter, 
        Fake
    }


    struct ProjectInfo {
        mapping(address => uint) kudosByUser;
        uint kudosTotal;
    }


    struct UserInfo {
        uint kudosLimit;
        uint kudosGiven;
        bool isJudge;
        mapping(uint => bool) grant;
    }



    struct UserIndex {
        bytes32[] projects;
        uint[] kudos;
        mapping(bytes32 => uint) kudosIdx;
    }


    struct VotePeriod {
        uint start;
        uint end;
    }


    address owner;


    VotePeriod votePeriod;


    mapping(address => UserInfo) users;



    mapping(address => UserIndex) usersIndex;


    mapping(bytes32 => ProjectInfo) projects;


    event Vote(

        address indexed voter,

        bytes32 indexed projectCode,

        uint indexed count
    );


    function ProjectKudos() {

        owner = msg.sender;

        votePeriod = VotePeriod(
            1479996000,     
            1482415200      
        );
    }


    function register(address userAddres, bool isJudge) onlyOwner {

        UserInfo user = users[userAddres];

        if (user.kudosLimit > 0) throw;

        if (isJudge)
            user.kudosLimit = KUDOS_LIMIT_JUDGE;
        else 
            user.kudosLimit = KUDOS_LIMIT_USER;

        user.isJudge = isJudge;

        users[userAddres] = user;
    }


    function giveKudos(string projectCode, uint kudos) duringVote {

        UserInfo giver = users[msg.sender];

        if (giver.kudosGiven + kudos > giver.kudosLimit) throw;

        bytes32 code = strToBytes(projectCode);
        ProjectInfo project = projects[code];

        giver.kudosGiven += kudos;
        project.kudosTotal += kudos;
        project.kudosByUser[msg.sender] += kudos;


        updateUsersIndex(code, project.kudosByUser[msg.sender]);

        Vote(msg.sender, sha3(projectCode), kudos);
    }


    function grantKudos(address userToGrant, uint reason) onlyOwner {

        UserInfo user = users[userToGrant];

        GrantReason grantReason = grantUintToReason(reason);

        if (grantReason != GrantReason.Facebook &&
            grantReason != GrantReason.Twitter) throw;




        if (user.isJudge) throw;


        if (user.grant[reason]) throw;


        user.kudosLimit += 100;


        user.grant[reason] = true;
    }







    function getProjectKudos(string projectCode) constant returns(uint) {
        bytes32 code = strToBytes(projectCode);
        ProjectInfo project = projects[code];
        return project.kudosTotal;
    }


    function getProjectKudosByUsers(string projectCode, address[] users) constant returns(uint[]) {
        bytes32 code = strToBytes(projectCode);
        ProjectInfo project = projects[code];
        mapping(address => uint) kudosByUser = project.kudosByUser;
        uint[] memory userKudos = new uint[](users.length);
        for (uint i = 0; i < users.length; i++) {
            userKudos[i] = kudosByUser[users[i]];    
       }

       return userKudos;
    }


    function getKudosPerProject(address giver) constant returns (bytes32[] projects, uint[] kudos) {
        UserIndex idx = usersIndex[giver];
        projects = idx.projects;
        kudos = idx.kudos;
    }


    function getKudosLeft(address addr) constant returns(uint) {
        UserInfo user = users[addr];
        return user.kudosLimit - user.kudosGiven;
    }


    function getKudosGiven(address addr) constant returns(uint) {
        UserInfo user = users[addr];
        return user.kudosGiven;
    }







    function updateUsersIndex(bytes32 code, uint kudos) private {

        UserIndex idx = usersIndex[msg.sender];
        uint i = idx.kudosIdx[code];


        if (i == 0) {
            i = idx.projects.length + 1;
            idx.projects.length += 1;
            idx.kudos.length += 1;
            idx.projects[i - 1] = code;
            idx.kudosIdx[code] = i;
        }

        idx.kudos[i - 1] = kudos;
    }


    function grantUintToReason(uint reason) private returns (GrantReason result) {
        if (reason == 0)  return GrantReason.Facebook;
        if (reason == 1)  return GrantReason.Twitter;
        return GrantReason.Fake;
    }


    function grantReasonToUint(GrantReason reason) private returns (uint result) {
        if (reason == GrantReason.Facebook) return 0;
        if (reason == GrantReason.Twitter)  return 1;
        return 3;
    }


    function strToBytes(string str) private returns (bytes32 ret) {

        if (bytes(str).length > 32) throw;

        assembly {
            ret := mload(add(str, 32))
        }
    } 







    modifier duringVote() {
        if (now < votePeriod.start) throw;
        if (now >= votePeriod.end) throw;
        _;
    }


    modifier onlyOwner() { 
        if (msg.sender != owner) throw;
        _;
    }
}

